import{_ as s,o as a,c as t,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"ESXi NVME 驱动降级方法","description":"","frontmatter":{"title":"ESXi NVME 驱动降级方法","date":"2020-6-14 20:7:17","category":"ESXi","tags":["ESXi"]},"headers":[],"relativePath":"posts/esxi-nvme-qu-dong-jiang-ji-fang-fa.md","filePath":"posts/esxi-nvme-qu-dong-jiang-ji-fang-fa.md","lastUpdated":1783006593000}'),n={name:"posts/esxi-nvme-qu-dong-jiang-ji-fang-fa.md"};function p(l,e,o,r,c,d){return a(),t("div",null,[...e[0]||(e[0]=[i(`<p>最近将Z390+i7-9700K的机器从ubuntu 18.04 -&gt; ESXi 6.7u3，用虚拟化来提高硬件资源利用率。因为ESXi 7.0阉割的驱动太多了，太麻烦，新特性也没吸引到我，所以还是6.7。</p><p>装完发现海康威视的C2000 Pro NVME SSD没认出来，目测还是驱动阉割的问题，搜了下确实如此，6.5和6.7的就能认出来。</p><p>群里有童鞋也遇到同样问题，就简单写了下做个记录。</p><p>解决方案有2种，一种是直接修改iso镜像，将驱动包替换掉，另一种更简单一点，用vib驱动包降级下驱动即可。</p><p>这里就说下第二种方法：</p><p>先开启ESXi主机的ssh服务，在系统界面或者web界面开启都可以</p><p>下载文件升级包vmware-ESXi-6.7.0-8169922-depot.zip，这里用DELL的： <a href="https://dl.dell.com/FOLDER04945367M/1/VMware-VMvisor-Installer-6.7.0-8169922.x86_64-DellEMC_Customized-A01.zip" target="_blank" rel="noreferrer">https://dl.dell.com/FOLDER04945367M/1/VMware-VMvisor-Installer-6.7.0-8169922.x86_64-DellEMC_Customized-A01.zip</a></p><p>下载完成后解压，把vib20文件夹中2个文件夹里的nvme驱动包scp到esxi主机的/tmp或者其他目录：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>vib20\\nvme</span></span>
<span class="line"><span>vib20\\vmware-esx-esxcli-nvme-plugin</span></span></code></pre></div><p>之后ssh到主机，执行命令安装：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#esxcli software vib install -v /tmp/VMware_bootbank_vmware-esx-esxcli-nvme-plugin_1.2.0.32-0.0.8169922.vib</span></span>
<span class="line"><span>#esxcli software vib install -v /tmp/VMW_bootbank_nvme_1.2.1.34-1vmw.670.0.0.8169922.vib</span></span></code></pre></div><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_NVME_%E9%A9%B1%E5%8A%A8%E9%99%8D%E7%BA%A7%E6%96%B9%E6%B3%95/1592136516206.png" alt=""></p><p>重启后，SSD就识别出来了。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/ESXi_NVME_%E9%A9%B1%E5%8A%A8%E9%99%8D%E7%BA%A7%E6%96%B9%E6%B3%95/1592136527438.png" alt=""></p><p>其他诸如网卡等其他外设，都可以用这种方法升级或者降级驱动。</p>`,15)])])}const _=s(n,[["render",p]]);export{m as __pageData,_ as default};
